import{_ as o,o as t,c as i,ae as a}from"./chunks/framework.jfJLTIcL.js";const u=JSON.parse('{"title":"Troubleshooting","description":"","frontmatter":{},"headers":[],"relativePath":"en/troubleshooting.md","filePath":"en/troubleshooting.md","lastUpdated":1775644124000}'),r={name:"en/troubleshooting.md"};function s(l,e,n,c,d,h){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h1><h2 id="_401-unauthorized" tabindex="-1"><code>401 Unauthorized</code> <a class="header-anchor" href="#_401-unauthorized" aria-label="Permalink to &quot;`401 Unauthorized`&quot;">​</a></h2><p>Check:</p><ul><li>The <code>Authorization</code> header is present</li><li>The header uses <code>Bearer &lt;token&gt;</code></li><li>You are using an external API key for <code>/v1/*</code></li><li>The key was not revoked</li></ul><h2 id="no-local-speech-model-is-active" tabindex="-1">No local speech model is active <a class="header-anchor" href="#no-local-speech-model-is-active" aria-label="Permalink to &quot;No local speech model is active&quot;">​</a></h2><p>If dictation or <code>/v1/audio/transcriptions</code> fails before transcription starts:</p><ul><li>Open <strong>Settings -&gt; Local speech models</strong></li><li>Download a built-in model such as <code>Whisper Base</code>, <code>Whisper Small</code>, or <code>SenseVoice</code>, or place a compatible Whisper.cpp <code>.bin</code> file in the models directory</li><li>Activate the model you want the host to use</li></ul><p>This applies only when <strong>Settings -&gt; Routing and models -&gt; STT mode</strong> is set to <code>Local</code>.</p><h2 id="a-settings-change-does-not-seem-to-take-effect" tabindex="-1">A settings change does not seem to take effect <a class="header-anchor" href="#a-settings-change-does-not-seem-to-take-effect" aria-label="Permalink to &quot;A settings change does not seem to take effect&quot;">​</a></h2><p>Settings now save automatically after each change.</p><p>If a dictation priority, provider, or routing change does not seem to apply:</p><ul><li>Wait until the settings footer switches back from <code>Saving...</code></li><li>Reopen <strong>Settings</strong> and confirm the new value is still selected</li><li>Retry dictation after the auto-save completes</li></ul><h2 id="cloud-stt-is-selected-but-transcription-still-fails" tabindex="-1">Cloud STT is selected but transcription still fails <a class="header-anchor" href="#cloud-stt-is-selected-but-transcription-still-fails" aria-label="Permalink to &quot;Cloud STT is selected but transcription still fails&quot;">​</a></h2><p>Check:</p><ul><li><strong>Settings -&gt; Routing and models -&gt; STT mode</strong> is set to <code>Cloud</code></li><li>A valid cloud STT provider is selected</li><li>The provider profile is enabled</li><li>The provider API key is configured</li><li>The cloud STT model name is valid for that provider</li></ul><h2 id="prompt-lab-smart-clean-returns-the-original-text" tabindex="-1">Prompt Lab <code>Smart Clean</code> returns the original text <a class="header-anchor" href="#prompt-lab-smart-clean-returns-the-original-text" aria-label="Permalink to &quot;Prompt Lab `Smart Clean` returns the original text&quot;">​</a></h2><p>This is often expected.</p><p><code>Smart Clean</code> in Prompt Lab uses only local cleanup rules. It does not call the selected provider, model, preset, or prompt override. If the input has no low-risk fillers, repetitions, or obvious self-repairs, the result may stay unchanged and the run may show <code>Local rules · &lt;1ms</code>.</p><h2 id="prompt-lab-polished-says-add-the-api-key-for-groq-in-settings-first" tabindex="-1">Prompt Lab <code>Polished</code> says <code>Add the API key for groq in Settings first</code> <a class="header-anchor" href="#prompt-lab-polished-says-add-the-api-key-for-groq-in-settings-first" aria-label="Permalink to &quot;Prompt Lab `Polished` says `Add the API key for groq in Settings first`&quot;">​</a></h2><p>This means the provider request was not allowed to start because the configured transform provider is missing an API key.</p><p>Check:</p><ul><li><strong>Settings -&gt; Provider profiles</strong> contains a valid API key for the selected provider</li><li>The provider profile is enabled</li><li>The chosen model exists for that provider</li></ul><p>Then reopen Prompt Lab or rerun the comparison.</p><h2 id="prompt-override-seems-ignored-in-prompt-lab" tabindex="-1">Prompt override seems ignored in Prompt Lab <a class="header-anchor" href="#prompt-override-seems-ignored-in-prompt-lab" aria-label="Permalink to &quot;Prompt override seems ignored in Prompt Lab&quot;">​</a></h2><p>Prompt overrides apply only to <code>Polished</code>.</p><p>If you paste a prompt override into a <code>Smart Clean</code> variant, it will not be used because <code>Smart Clean</code> is intentionally local-only in V1.</p><h2 id="whisper-rs-sys-build-failure" tabindex="-1"><code>whisper-rs-sys</code> build failure <a class="header-anchor" href="#whisper-rs-sys-build-failure" aria-label="Permalink to &quot;`whisper-rs-sys` build failure&quot;">​</a></h2><p>If <code>npm run dev</code> or <code>cargo check</code> fails while compiling <code>whisper-rs-sys</code> on Windows:</p><ul><li>Try <code>npm run cargo:check</code> first because it auto-detects common Windows <code>libclang</code> locations</li><li>Make sure a 64-bit <code>libclang.dll</code> is available on the machine</li><li>Set <code>LIBCLANG_PATH</code> to the directory that contains that DLL</li><li>Retry the build after reopening the shell if needed</li></ul><p>This is a build prerequisite for the local Whisper runtime, not a runtime API configuration issue.</p><h2 id="onnx-runtime-or-sensevoice-startup-failure-on-windows" tabindex="-1">ONNX Runtime or SenseVoice startup failure on Windows <a class="header-anchor" href="#onnx-runtime-or-sensevoice-startup-failure-on-windows" aria-label="Permalink to &quot;ONNX Runtime or SenseVoice startup failure on Windows&quot;">​</a></h2><p>If the desktop app fails while preparing the built-in SenseVoice runtime:</p><ul><li>Start the app through the repository scripts such as <code>npm run dev</code>, <code>npm run build</code>, or <code>npm run cargo:check</code></li><li>Avoid launching <code>cargo</code> directly from a shell that skips <code>scripts/with-libclang.mjs</code></li><li>Retry after deleting a partial ONNX Runtime download only if the script reports a corrupted archive</li></ul><p>The repository startup scripts now download and wire up the required Windows ONNX Runtime files automatically.</p><h2 id="macos-global-shortcuts-do-not-trigger" tabindex="-1">macOS global shortcuts do not trigger <a class="header-anchor" href="#macos-global-shortcuts-do-not-trigger" aria-label="Permalink to &quot;macOS global shortcuts do not trigger&quot;">​</a></h2><p>Check:</p><ul><li><strong>System Settings -&gt; Privacy &amp; Security -&gt; Accessibility</strong> includes the terminal, Codex host, or packaged VILab app you are launching</li><li>You are testing on a recent build that includes the macOS event-listener shortcut backend</li><li>If you picked a single-key shortcut, it is not being intercepted by another app or a system-level feature</li><li>The shortcut does not conflict with obvious system-reserved combinations such as <code>Cmd+Space</code> or <code>Cmd+Option+Space</code></li></ul><p>The current default macOS shortcut is <code>Cmd+Shift+Option+D</code>.</p><h2 id="macos-dictation-finishes-but-the-recording-animation-looks-flat" tabindex="-1">macOS dictation finishes but the recording animation looks flat <a class="header-anchor" href="#macos-dictation-finishes-but-the-recording-animation-looks-flat" aria-label="Permalink to &quot;macOS dictation finishes but the recording animation looks flat&quot;">​</a></h2><p>If text still transcribes correctly, the microphone input is usually reaching the model.</p><p>Check:</p><ul><li>The app has microphone permission</li><li>You are running version <code>0.1.6</code> or later, which boosts the macOS recording level used by the overlay animation</li><li>You are testing from the latest <code>npm run dev</code> session or a rebuilt packaged app</li></ul><p>This symptom usually indicates a UI level-mapping issue, not a transcription failure.</p><h2 id="the-windows-release-app-exits-during-startup" tabindex="-1">The Windows release app exits during startup <a class="header-anchor" href="#the-windows-release-app-exits-during-startup" aria-label="Permalink to &quot;The Windows release app exits during startup&quot;">​</a></h2><p>If the packaged desktop app opens and immediately exits on Windows:</p><ul><li>Open <code>%APPDATA%\\\\com.vilab.desktop\\\\startup-trace.log</code></li><li>Create an issue at <a href="https://github.com/Ro-In-AI/VILab-public/issues" target="_blank" rel="noreferrer">GitHub Issues</a></li><li>Attach <code>startup-trace.log</code> and include the Windows version, the installer version, and whether the crash happens on first launch</li></ul><p>If <code>%APPDATA%\\\\com.vilab.desktop\\\\startup-trace.log</code> is empty or missing, mention that in the issue as well.</p><h2 id="service-unreachable" tabindex="-1">Service unreachable <a class="header-anchor" href="#service-unreachable" aria-label="Permalink to &quot;Service unreachable&quot;">​</a></h2><p>Check:</p><ul><li>The desktop app is running</li><li>The configured <strong>Server URL</strong> is correct</li><li>The host firewall allows inbound traffic on the service port</li><li>The client is calling the reachable LAN IP or hostname</li></ul><h2 id="lan-clients-cannot-connect" tabindex="-1">LAN clients cannot connect <a class="header-anchor" href="#lan-clients-cannot-connect" aria-label="Permalink to &quot;LAN clients cannot connect&quot;">​</a></h2><p>Check:</p><ul><li>The host is not still bound only to <code>127.0.0.1</code></li><li>The client and host are on the same network</li><li>The service port is not blocked by security software</li></ul><h2 id="wrong-model-error" tabindex="-1">Wrong model error <a class="header-anchor" href="#wrong-model-error" aria-label="Permalink to &quot;Wrong model error&quot;">​</a></h2><p><code>/v1/audio/transcriptions</code> accepts only:</p><ul><li>The current public STT model alias returned by <code>/health</code></li></ul><p>If you send any other model value, the service returns <code>400 Unsupported model</code>.</p><h2 id="unsupported-audio-format" tabindex="-1">Unsupported audio format <a class="header-anchor" href="#unsupported-audio-format" aria-label="Permalink to &quot;Unsupported audio format&quot;">​</a></h2><p>The current local HTTP transcription endpoint accepts WAV audio in this phase.</p><p>If you send another container or codec, convert it to WAV before calling <code>/v1/audio/transcriptions</code>.</p>',60)])])}const m=o(r,[["render",s]]);export{u as __pageData,m as default};
